#include <stdio.h>
#include <string.h>
#include <windows.h>
#include <stdlib.h>


void printCenter(const char *mess) {
    int i = 0, count = 0;
    while (mess[i] != '\0')
    {
        if ((mess[i++] & 0xC0) != 0X80) count++;
    }
    int space = (120 - count) / 2 + 1;
    printf ("%*s%s", space, "", mess);
}



